setupProduct.query:
#graphql
  mutation GenericProductMetafieldsProductCreate($product: ProductCreateInput!) {
    productCreate(product: $product) {
      product { id title }
      userErrors { field message }
    }
  }

set.query:
mutation NaturalProductMetafieldsSet($metafields: [MetafieldsSetInput!]!) {
  metafieldsSet(metafields: $metafields) {
    metafields {
      namespace
      key
      type
      value
    }
    userErrors {
      field
      message
      code
      elementIndex
    }
  }
}

readAfterSet.query:
query NaturalProductMetafieldsRead($id: ID!) {
  product(id: $id) {
    id
    material: metafield(namespace: "custom", key: "generic_material") {
      namespace
      key
      type
      value
    }
    metafields(first: 10, namespace: "custom") {
      nodes {
        namespace
        key
        type
        value
      }
    }
  }
}

delete.query:
mutation NaturalProductMetafieldsDelete($metafields: [MetafieldIdentifierInput!]!) {
  metafieldsDelete(metafields: $metafields) {
    deletedMetafields {
      ownerId
      namespace
      key
    }
    userErrors {
      field
      message
    }
  }
}

readAfterDelete.query:
